const listAttachmentObjectDeletionCandidates = `-- name: ListAttachmentObjectDeletionCandidates :many
SELECT
    a.id,
    a.object_key,
    a.status
FROM attachments AS a
WHERE
  (
      a.status = 'expired'
      AND a.updated_at < $1
      AND NOT EXISTS (
          SELECT 1
          FROM message_attachments AS ma
          WHERE ma.attachment_id = a.id
      )
  )
  OR (
      a.status = 'failed'
      AND a.failed_at IS NOT NULL
      AND a.failed_at <= $2
      AND NOT EXISTS (
          SELECT 1
          FROM message_attachments AS ma
          WHERE ma.attachment_id = a.id
      )
  )
  OR (
      a.status = 'detached'
      AND a.updated_at <= $3
  )
ORDER BY
    CASE
        WHEN a.status = 'expired' THEN 0
        WHEN a.status = 'detached' THEN 1
        ELSE 2
    END ASC,
    COALESCE(a.failed_at, a.updated_at) ASC,
    a.id ASC
LIMIT $4
`

